const r = await tools.exec_command({
  cmd: "find /app/eval_fp8 -type f -maxdepth 3 -printf '%p %s\n' | sort && python - <<'PY'
import glob,json,collections,os
for f in glob.glob('/app/eval_fp8/**/output*.jsonl',recursive=True):
 print('FILE',f)
 lens=[]; reasons=collections.Counter()
 for line in open(f):
  x=json.loads(line); lens.append(x.get('num_generated_tokens',x.get('output_tokens',x.get('generation_tokens',-1))))
  for k in ['finish_reason','stop_reason']:
   if k in x: reasons[str(x[k])]+=1
 print('n',len(lens),'lens',sorted(lens)[-10:],'keys',json.loads(open(f).readline()).keys(),'reasons',reasons)
PY",
  workdir: "/app",
  yield_time_ms: 10000,
  max_output_tokens: 5000
});
text(r.output);

